28	template<typename T>
29	inline void agm_update(T& x, T& y)
30	{
31	    typedef typing::decplx_t<T> RT;
32	
33	    T xnext = (x + y) * (RT)0.5;
34	    T ynext = std::sqrt(x * y);
35	
36	    x = xnext;
37	    y = ynext;
38	}
39	
40	template<typename T>
41	static ExitStatus
42	rf0(const T& x, const T& y, const double& rerr, T& res)
43	{
44	    typedef typing::decplx_t<T> RT;
45	    ExitStatus status = ExitStatus::success;
46	    double rsq = 2.0 * std::sqrt(rerr);
47	
48	    T xm = std::sqrt(x);
49	    T ym = std::sqrt(y);
50	    unsigned int m = 0;
51	    while ( std::abs(xm - ym) >= rsq * std::fmin(std::abs(xm), std::abs(ym)) )
52	    {
53		if ( m > config::max_iter )
54		{
55		    status = ExitStatus::n_iter;
56		    break;
57		}
58	
59		agm_update(xm, ym);
60	
61		++m;
62	    }
63	
64	    res = (RT)(constants::pi) / (xm + ym);
65	    return status;
66	}
67	
68	
69	template<typename T>
70	ExitStatus
71	rf(const T& x, const T& y, const T& z, const double& rerr, T& res)
72	{
73	    typedef typing::decplx_t<T> RT;
74	
75	    T cct1[3];
76	    T cct2[3];
77	
78	    ExitStatus status = ExitStatus::success;
79	#ifndef ELLINT_NO_VALIDATE_RELATIVE_ERROR_BOUND
80	    if ( argcheck::invalid_rerr(rerr, 3.0e-4) )
81	    {
82		res = typing::nan<T>();
83		return ExitStatus::bad_rerr;
84	    }
85	#endif
86	
87	    if ( argcheck::ph_good(x) && argcheck::ph_good(y) && argcheck::ph_good(z) )
88	    {
89		if ( argcheck::isinf(x) || argcheck::isinf(y) || argcheck::isinf(z) )
90		{
91		    res = T(0.0);
92		    return ExitStatus::success;
93		}
94	    } else {
95		res = typing::nan<T>();
96		return ExitStatus::bad_args;
97	    }
98	
99	    cct1[0] = T(x);
100	    cct1[1] = T(y);
101	    cct1[2] = T(z);
102	    std::sort(std::begin(cct1), std::end(cct1), util::abscmp<T>);
103	    T xm = cct1[0];
104	    T ym = cct1[1];
105	    T zm = cct1[2];
106	    if ( argcheck::too_small(xm) )
107	    {
108		if ( argcheck::too_small(ym) )
109		{
110		    status = ExitStatus::singular;
111		    res = typing::huge<T>();
112		    return status;
113		} else {
114		    T tmpres;
115		    status = rf0(ym, zm, rerr * (RT)0.5, tmpres);
116		    /* Correction for non-zero x, see Eq. 19.27.3 in
117		     * https://dlmf.nist.gov/19.27.E3 */
118		    res = tmpres - std::sqrt(xm / (ym * zm));
119		    return status;
120		}
121	    }
122	
123	    T Am = arithmetic::sum2(cct1) / (RT)3.0;
124	    T xxm = Am - xm;
125	    T yym = Am - ym;
126	    RT fterm = std::abs(std::max({xxm, yym, Am - zm}, util::abscmp<T>)) /
127	               arithmetic::ocrt(3.0 * rerr);
128	    unsigned int m = 0;
129	    RT aAm;
130	    while ( (aAm = std::abs(Am)) <= fterm ||
131		    aAm <= std::abs(std::max({xxm, yym, Am - zm}, util::abscmp<T>)) )
132	    {
133		if ( m > config::max_iter )
134		{
135		    status = ExitStatus::n_iter;
136		    break;
137		}
138		cct1[0] = cct2[2] = std::sqrt(xm);
139		cct1[1] = cct2[0] = std::sqrt(ym);
140		cct1[2] = cct2[1] = std::sqrt(zm);
141		T lam = arithmetic::dot2(cct1, cct2);
142	        Am = (Am + lam) * (RT)0.25;
143	        xm = (xm + lam) * (RT)0.25;
144	        ym = (ym + lam) * (RT)0.25;
145	        zm = (zm + lam) * (RT)0.25;
146	        xxm *= (RT)0.25;
147	        yym *= (RT)0.25;
148	        fterm *= (RT)0.25;
149	
150	        ++m;
151	    }
152	    /* Burn some extra cycles re-balancing Am as the "true" centroid. */
153	    cct1[0] = xm;
154	    cct1[1] = ym;
155	    cct1[2] = zm;
156	    Am = arithmetic::sum2(cct1) / (RT)3.0;
157	    xxm /= Am;
158	    yym /= Am;
159	    /* Prepare the E_2 and E_3 terms used in the expansion */
160	    T zzm = -(xxm + yym);
161	    T e2 = xxm * yym - zzm * zzm;
162	    T e3 = xxm * (yym * zzm);
163	    /* Evaluate the 7th-degree expansion using the E_2 and E3 terms, following
164	     * Eq. 19.36.1 of [1], https://dlmf.nist.gov/19.36.E1
165	     * The order of expansion is higher than that in Eq. (14) of Ref. [2]. */
166	    T s = arithmetic::comp_horner(e2, constants::RF_C1);
167	    s += e3 * (arithmetic::comp_horner(e2, constants::RF_C2) +
168	               e3 * (RT)(constants::RF_c33));
169	    s /= (RT)(constants::RF_DENOM);
170	    s += (RT)1.0;
171	
172	    res = s / std::sqrt(Am);
